// Flatten one anonymous beacon into a clean, flat row.
// sendBeacon delivers JSON under $json.body; be tolerant if it arrives as a raw string.
const out = [];
for (const item of $input.all()) {
  let b = item.json.body;
  if (typeof b === 'string') { try { b = JSON.parse(b); } catch (e) { b = {}; } }
  if (!b || typeof b !== 'object') b = {};
  const t = b.t ? new Date(Number(b.t)) : new Date();
  const iso = isNaN(t.getTime()) ? new Date().toISOString() : t.toISOString();
  const s = (v) => (v === undefined || v === null) ? '' : v;
  out.push({ json: {
    when: iso,
    event: s(b.event),
    cid: s(b.cid),
    sid: s(b.sid),
    ref: s(b.ref),
    chapter: s(b.id),
    chapterIndex: s(b.chapterIndex),
    name: s(b.name),
    returning: s(b.returning),
    durationS: s(b.durationS),
    furthest: s(b.furthest),
    furthestIndex: s(b.furthestIndex),
    lang: s(b.lang),
    w: s(b.w),
    h: s(b.h),
    dpr: s(b.dpr),
    standalone: s(b.standalone),
    ua: s(b.ua),
    ver: s(b.ver)
  } });
}
return out;

